export default function USMap({ selectedStates, onToggleState }: USMapProps) {
  const [hoveredState, setHoveredState] = useState<string | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const tooltipRef = useRef<HTMLDivElement>(null);

  const handleMouseEnter = (stateAbbr: string, e: React.MouseEvent<SVGPathElement>) => {
    setHoveredState(stateAbbr);
    const rect = (e.currentTarget as SVGPathElement).getBoundingClientRect();
    setTooltipPos({ 
      x: rect.left + rect.width / 2, 
      y: rect.top - 10 
    });
  };

  const handleMouseLeave = () => {
    setHoveredState(null);
  };

  return (
    <div style={{ position: 'relative', marginBottom: '20px' }}>
      <style>
        {`
          .us-map-svg {
            width: 100%;
            max-width: 100%;
            height: auto;
            background-color: #1A1A1A;
            border-radius: 6px;
            border: 1px solid #1F2937;
          }

          .us-map-state {
            cursor: pointer;
            opacity: 0.85;
            transition: opacity 0.2s ease, filter 0.2s ease;
          }

          .us-map-state:hover {
            opacity: 1;
            filter: brightness(1.1);
          }

          .us-map-state-selected {
            opacity: 1;
          }

          .us-map-tooltip {
            position: fixed;
            background-color: #111111;
            color: #39FF14;
            padding: 8px 12px;
            border-radius: 4px;
            font-size: 12px;
            font-weight: 600;
            pointer-events: none;
            border: 1px solid #39FF14;
            z-index: 1000;
            white-space: nowrap;
            transform: translateX(-50%);
          }
        `}
      </style>

      <svg
        viewBox="0 0 960 600"
        className="us-map-svg"
      >
        {Object.entries(US_STATE_DATA).map(([stateAbbr, { name, d }]) => (
          <g key={stateAbbr}>
            <path
              d={d}
              className={`us-map-state ${selectedStates.includes(stateAbbr) ? 'us-map-state-selected' : ''}`}
              fill={selectedStates.includes(stateAbbr) ? '#39FF14' : '#2D3748'}
              stroke="#0A0A0A"
              strokeWidth="0.5"
              onClick={() => onToggleState(stateAbbr)}
              onMouseEnter={(e) => handleMouseEnter(stateAbbr, e)}
              onMouseLeave={handleMouseLeave}
            />
          </g>
        ))}
      </svg>

      {hoveredState && (
        <div
          ref={tooltipRef}
          className="us-map-tooltip"
          style={{
            left: `${tooltipPos.x}px`,
            top: `${tooltipPos.y}px`,
          }}
        >
          {US_STATE_DATA[hoveredState]?.name}
        </div>
      )}
    </div>
  );
}
